tinymce.PluginManager.add('stream', function(editor, url) {
    //  editor.ui.registry.addIcon('stream', '<svg class="icon"><use xlink:href="../../svg/custom-icons.svg#stream"></use></svg>');
   // editor.ui.registry.addIcon('stream', '<svg width="24" height="24"><use xlink:href="../../tinymce/svg/custom-icons.svg#stream"></use></svg>');
    editor.ui.registry.addIcon('stream', '<?xml version="1.0" encoding="utf-8"?>\n' +
        '<!-- Generator: Adobe Illustrator 16.0.0, SVG Export Plug-In . SVG Version: 6.00 Build 0)  -->\n' +
        '<!DOCTYPE svg PUBLIC "-//W3C//DTD SVG 1.1//EN" "http://www.w3.org/Graphics/SVG/1.1/DTD/svg11.dtd">\n' +
        '<svg version="1.1" id="Layer_1" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink" x="0px" y="0px"\n' +
        '\t width="18.306px" height="19px" viewBox="0 0 18.306 19" enable-background="new 0 0 18.306 19" xml:space="preserve">\n' +
        '<g>\n' +
        '\t<g>\n' +
        '\t\t<path fill-rule="evenodd" clip-rule="evenodd" fill="#020000" d="M0.306,19h18v-2h-18V19z M0.306,0v16h18V0H0.306z M16.306,14h-14\n' +
        '\t\t\tV2h14V14z M6.306,4.642v7.217l6.25-3.608L6.306,4.642z"/>\n' +
        '\t</g>\n' +
        '</g>\n' +
        '</svg>');

    var openDialog = function () {
        var cid = editor.getParam('content_id');
        var ctype = editor.getParam('content_type');
        var module_code = editor.getParam('module_code');
        var query = '?cid='+cid+'&ctype='+ctype+'&moduleCode='+module_code;
            return editor.windowManager.openUrl({
                url: tinymce.baseURL + '/plugins/stream/scripts/stream.php'+query,
                title: 'Stream',
                width: 400,
                height: 250,

            });

    };


    editor.ui.registry.addButton('stream', {
        tooltip: 'Stream',
        icon: 'stream',
        onAction: function () {
            // Open window
            openDialog();
        }

    });

    // Adds a menu item, which can then be included in any menu via the menu/menubar configuration
    editor.ui.registry.addMenuItem('stream', {
        text: 'Stream',
        icon: 'stream',
        onAction: function () {
            // Open window
            openDialog();
        }
    });
});